function executeCard(context) {
  const player = battle.players.find(p => p.playerId === playerId);
  if (!player || player.actionPoints < 1) {
    return { success: false, message: '行动点不足，无法使用急救包' };
  }
  const target = selectTarget({ filter: 'ally', range: 99 });
  if (!target) return { success: false, message: '请选择一名友方棋子' };
  player.actionPoints -= 1;
  const result = healDamage(target, target, 15, battle, 'sample-active-card');
  return { success: true, message: `急救包：为${target.name || target.templateId}回复${result.heal}点生命值` };
}
